// Robustly parse Gemini generateContent response into JSON

// 1) Collect the raw text from Gemini
let rawText = "";

const candidate = $json.candidates?.[0];
if (candidate?.content?.parts) {
  rawText = candidate.content.parts
    .map(p => (p.text ?? ""))
    .join("\n");
} else {
  rawText = "";
}

function extractJsonString(raw) {
  if (!raw) return "";

  let s = raw.trim();

  // Remove leading code fences: ``` or
  s = s.replace(/^```[a-zA-Z]*\s*/, "");
  // Remove trailing fence at the very end
  s = s.replace(/```$/, "").trim();
  // Remove any remaining fences inside
  s = s.replace(/```[a-zA-Z]*\s*/g, "").replace(/```/g, "");

  // Try parsing the whole string first
  try {
    JSON.parse(s);
    return s;
  } catch {}

  // Fallback: try to extract the first {...} block
  const start = s.indexOf("{");
  const end = s.lastIndexOf("}");
  if (start !== -1 && end !== -1 && end > start) {
    const candidateJson = s.slice(start, end + 1);
    try {
      JSON.parse(candidateJson);
      return candidateJson;
    } catch {}
  }

  // If we reach here, we couldn't find valid JSON
  throw new Error("Could not extract valid JSON from Gemini output");
}

let parsed;

try {
  const jsonString = extractJsonString(rawText);
  parsed = JSON.parse(jsonString);
      console.log('parsed output', parsed);
} catch (error) {
  // Fallback: keep the text so you still see what the model returned
  parsed = {
    extractedSections: [],
    executiveSummary: rawText || "LLM did not return valid JSON.",
    confidenceScore: 50,
    parseError: error.message
  };
}

return [
  {
    json: {
      success: true,
      data: parsed,
      rawText
    }
  }
];
